import React, { useEffect, useState } from "react";
import API from "../services/api";
import Navbar from "../components/Navbar";

function Enclosures() {
  const [enclosures, setEnclosures] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    type: "",
    capacity: "",
    location: "",
    status: "",
  });

  useEffect(() => {
    fetchEnclosures();
  }, []);

  const fetchEnclosures = async () => {
    try {
      const res = await API.get("/enclosures");
      setEnclosures(res.data);
    } catch (error) {
      console.error("Error fetching enclosures:", error);
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setFormData({
      name: "",
      type: "",
      capacity: "",
      location: "",
      status: "",
    });
    setEditingId(null);
  };

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const payload = {
      name: formData.name,
      type: formData.type,
      capacity: Number(formData.capacity),
      location: formData.location,
      status: formData.status,
    };

    try {
      if (editingId) {
        await API.put(`/enclosures/${editingId}`, payload);
        alert("Enclosure updated successfully");
      } else {
        await API.post("/enclosures", payload);
        alert("Enclosure added successfully");
      }

      resetForm();
      fetchEnclosures();
    } catch (error) {
      console.error("Error saving enclosure:", error);

      if (error.response?.data) {
        const data = error.response.data;
        if (typeof data === "object") {
          const firstError = Object.values(data)[0];
          alert(firstError);
        } else {
          alert("Failed to save enclosure");
        }
      } else {
        alert("Failed to save enclosure");
      }
    }
  };

  const handleEdit = (enclosure) => {
    setEditingId(enclosure.id);
    setFormData({
      name: enclosure.name || "",
      type: enclosure.type || "",
      capacity: enclosure.capacity || "",
      location: enclosure.location || "",
      status: enclosure.status || "",
    });

    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleDelete = async (id) => {
    const confirmDelete = window.confirm(
      "Are you sure you want to delete this enclosure?"
    );
    if (!confirmDelete) return;

    try {
      await API.delete(`/enclosures/${id}`);
      alert("Enclosure deleted successfully");
      fetchEnclosures();
    } catch (error) {
      console.error("Error deleting enclosure:", error);
      alert("Failed to delete enclosure");
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>
        <div style={styles.header}>
          <h1 style={styles.title}>Enclosures Management</h1>
          <p style={styles.subtitle}>
            Add, update, view, and manage zoo enclosures from one place.
          </p>
        </div>

        <div style={styles.formCard}>
          <h2 style={styles.cardTitle}>
            {editingId ? "Update Enclosure" : "Add New Enclosure"}
          </h2>

          <form onSubmit={handleSubmit} style={styles.formGrid}>
            <input
              type="text"
              name="name"
              placeholder="Enclosure Name"
              value={formData.name}
              onChange={handleChange}
              style={styles.input}
            />

            <input
              type="text"
              name="type"
              placeholder="Type (Mammal, Bird, Reptile...)"
              value={formData.type}
              onChange={handleChange}
              style={styles.input}
            />

            <input
              type="number"
              name="capacity"
              placeholder="Capacity"
              value={formData.capacity}
              onChange={handleChange}
              style={styles.input}
            />

            <input
              type="text"
              name="location"
              placeholder="Location"
              value={formData.location}
              onChange={handleChange}
              style={styles.input}
            />

            <select
              name="status"
              value={formData.status}
              onChange={handleChange}
              style={styles.input}
            >
              <option value="">Select Status</option>
              <option value="Available">Available</option>
              <option value="Full">Full</option>
              <option value="Under Maintenance">Under Maintenance</option>
            </select>

            <div style={styles.buttonRow}>
              <button type="submit" style={styles.primaryBtn}>
                {editingId ? "Update Enclosure" : "Add Enclosure"}
              </button>

              {editingId && (
                <button
                  type="button"
                  style={styles.cancelBtn}
                  onClick={resetForm}
                >
                  Cancel
                </button>
              )}
            </div>
          </form>
        </div>

        <div style={styles.listSection}>
          <h2 style={styles.cardTitle}>Enclosures List</h2>

          {loading ? (
            <p>Loading enclosures...</p>
          ) : enclosures.length === 0 ? (
            <p>No enclosures found.</p>
          ) : (
            <div style={styles.grid}>
              {enclosures.map((enclosure) => (
                <div key={enclosure.id} style={styles.enclosureCard}>
                  <h3 style={styles.enclosureName}>{enclosure.name}</h3>
                  <p><strong>Type:</strong> {enclosure.type}</p>
                  <p><strong>Capacity:</strong> {enclosure.capacity}</p>
                  <p><strong>Location:</strong> {enclosure.location}</p>
                  <p><strong>Status:</strong> {enclosure.status}</p>
                  <p>
                    <strong>Animals Assigned:</strong>{" "}
                    {enclosure.animals?.length || 0}
                  </p>

                  <div style={styles.actionRow}>
                    <button
                      style={styles.editBtn}
                      onClick={() => handleEdit(enclosure)}
                    >
                      Edit
                    </button>

                    <button
                      style={styles.deleteBtn}
                      onClick={() => handleDelete(enclosure.id)}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "linear-gradient(135deg, #eef2ff, #f8fafc)",
    fontFamily: "Arial, sans-serif",
  },
  container: {
    width: "90%",
    maxWidth: "1200px",
    margin: "0 auto",
    padding: "30px 0 50px",
  },
  header: {
    background: "linear-gradient(135deg, #ffffff, #eff6ff)",
    padding: "30px",
    borderRadius: "20px",
    boxShadow: "0 10px 24px rgba(0,0,0,0.08)",
    marginBottom: "25px",
  },
  title: {
    fontSize: "2.2rem",
    color: "#111827",
    marginBottom: "10px",
  },
  subtitle: {
    color: "#4b5563",
    fontSize: "1rem",
    lineHeight: "1.7",
  },
  formCard: {
    background: "#fff",
    padding: "25px",
    borderRadius: "18px",
    boxShadow: "0 8px 20px rgba(0,0,0,0.08)",
    marginBottom: "30px",
  },
  cardTitle: {
    fontSize: "1.5rem",
    marginBottom: "20px",
    color: "#111827",
  },
  formGrid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))",
    gap: "16px",
  },
  input: {
    padding: "13px 15px",
    borderRadius: "10px",
    border: "1px solid #cbd5e1",
    fontSize: "1rem",
    outline: "none",
  },
  buttonRow: {
    display: "flex",
    gap: "12px",
    alignItems: "center",
    flexWrap: "wrap",
  },
  primaryBtn: {
    background: "#2563eb",
    color: "#fff",
    border: "none",
    padding: "12px 18px",
    borderRadius: "10px",
    cursor: "pointer",
    fontWeight: "bold",
  },
  cancelBtn: {
    background: "#6b7280",
    color: "#fff",
